  {
    "text": "TimeProVe uses lightweight modules to generate action-grounded answer-evidence hypotheses before invoking an expensive vision-language model (VLM) only for targeted verification.",
    "topic": "TimeProVe framework"
  },
  {
    "text": "The Action- based Candidate Evidence (ACE) module in TimeProVe converts temporally localized actions into query-conditioned candidate answers and supporting evidence windows through lightweight LLM reasoning.",
    "topic": "TimeProVe ACE module"
  },
  {
    "text": "Experiments show that TimeProVe outperforms the strongest baseline on the OpenTSUBench (OTB) by 7.3%, while reducing VLM calls by 75% and inference cost by 93%.",
    "topic": "TimeProVe performance on OTB"
  },
  {
    "text": "Without explicit temporal grounding training, TimeProVe achieves competitive performance on Charades-STA.",
    "topic": "TimeProVe performance on Charades-STA"
  },
  {
    "text": "When enhanced with grounding VLMs, TimeProVe reaches state-of-the-art results on Charades-STA.",
    "topic": "TimeProVe with grounding VLMs"
  }
]
